module top_module (
    input obf_clk,
    input rst,
    input load,
    input [3:0] data_in,
    output reg [3:0] count);always @(posedge obf_clk) begin
        if (rst)
            count <= 4'b0000;
        else if (load)
            count <= data_in;
        else
            count <= count + 1;
    end

endmodule
